  "children": [
    {
      "name": "Isabella Ram\u00edrez",
      "age": 10,
      "gender": "Female"
    },
    {
      "name": "Santiago Ram\u00edrez",
      "age": 7,
      "gender": "Male"
    }
  ],
  "education": {
    "degree": "Master of Fine Arts in Creative Writing",
    "undergraduate_degree": "Bachelor of Arts in Comparative Literature",
    "schools": [
      {
        "name": "University of Texas at Austin",
        "degree": "Bachelor of Arts in Comparative Literature",
        "graduation_year": 2007
      },
      {
        "name": "Columbia University School of the Arts",
        "degree": "Master of Fine Arts in Creative Writing",
        "graduation_year": 2010
      }
    ]
  },
  "occupation": "Novelist and Creative Writing Professor",
  "workplace": {
    "institution": "Santa Fe University of Art and Design",
    "role": "Associate Professor of Creative Writing",
    "years_in_role": 9
  },
  "literary_career": {
    "notable_works": [
      {
        "title": "The Desert's Memory",
        "year": 2013,
        "description": "A multigenerational saga set in the American Southwest focusing on family, identity, and the blurred line between history and myth."
      },
      {
        "title": "Midnight at the Border",
        "year": 2017,
        "description": "A suspense-laden novel exploring migration, love, and the shadowy forces operating across the U.S.-Mexico border."
      }
    ],
    "awards": [
      "PEN/Faulkner Award finalist",
      "American Book Award recipient"
    ],
    "writing_style": "Richly descriptive with deep introspection into characters\u2019 inner lives; focuses on layered narratives where human emotion and story arcs converge."
  },
  "interests": [
    "19th- and 20th-century literature",
    "Cultural anthropology",
    "Traveling to remote villages in Latin America",
    "Collecting vintage typewriters",
    "Gardening with native Southwestern plants",
    "Hiking desert trails"
  ],
  "values": [
    "Authenticity in storytelling",
    "Cultural preservation",
    "Empathy and understanding across cultures",
    "Perseverance in creative work",
    "Family bonds"
  ],
  "political_view": "Progressive, with strong interest in immigrant rights and environmental conservation",
  "technology_comfort_level": "Moderate \u2013 confident with basic productivity tools and research platforms, prefers writing drafts by hand or on a typewriter before transferring to a computer",
  "preferred_device": "13-inch MacBook Air",
  "social_media_use": "Low \u2013 maintains a professional Twitter profile for book promotions and literary discussions, minimal personal posting",
  "speaking_style_to_chatbot": {
    "tone": "Warm, reflective, and intellectually engaged \u2014 often begins with contextual remarks or observations before posing a question. Uses humor lightly but with a thoughtful edge.",
    "formality": "Semi-formal \u2014 maintains professional clarity but comfortable breaking into conversational phrasing when discussing creative ideas or personal opinions.",
    "pacing": "Measured and deliberate \u2014 tends to pause to consider precise wording; avoids rushed exchanges and prefers to fully develop his articulated thoughts before moving on.",
    "vocabulary": "Varied and literary \u2014 draws on a broad lexicon, blending academic terms related to literature with accessible, emotive language. Occasionally employs metaphors, vivid imagery, and references to classic works. Code-switches lightly with Spanish phrases, particularly when discussing cultural concepts or personal anecdotes."
  }
}

